const sendQuote = `-- name: SendQuote :one
UPDATE quotes SET status = 'sent', version = version + 1, valid_until = COALESCE($2, valid_until)
WHERE id = $1
RETURNING id, public_id, organization_id, website_id, customer_id, rfq_id, sales_rep_user_id, status, currency, version, valid_until, subtotal, created_at, updated_at
`

type SendQuoteParams struct {
	ID         int64              `json:"id"`
	ValidUntil pgtype.Timestamptz `json:"valid_until"`
}

// SendQuote moves the quote to 'sent' and bumps the version; the caller writes
// the matching quote_revisions snapshot in the same transaction.
func (q *Queries) SendQuote(ctx context.Context, arg SendQuoteParams) (Quote, error) {
	row := q.db.QueryRow(ctx, sendQuote, arg.ID, arg.ValidUntil)
	var i Quote
	err := row.Scan(
		&i.ID,
		&i.PublicID,
		&i.OrganizationID,
		&i.WebsiteID,
		&i.CustomerID,
		&i.RfqID,
		&i.SalesRepUserID,
		&i.Status,
		&i.Currency,
		&i.Version,
		&i.ValidUntil,
		&i.Subtotal,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

